<template>
  <div class="canvas-controls">
    <div class="control-group">
      <div class="zoom-controls">
        <button class="control-btn" @click="zoomIn" title="放大">
          <svg class="icon" viewBox="0 0 24 24" width="16" height="16">
            <path d="M19 13h-6v6h-2v-6H5v-2h6V5h2v6h6v2z"/>
          </svg>
        </button>
        <div class="zoom-level">{{ Math.round(scale * 100) }}%</div>
        <button class="control-btn" @click="zoomOut" title="缩小">
          <svg class="icon" viewBox="0 0 24 24" width="16" height="16">
            <path d="M19 13H5v-2h14v2z"/>
          </svg>
        </button>
      </div>
    </div>
    <div class="control-group">
      <button class="control-btn reset-btn" @click="resetViewport" title="重置视图">
        <svg class="icon" viewBox="0 0 24 24" width="16" height="16">
          <path d="M12 8V4l8 8-8 8v-4H4V8h8zm-8 8h6v2H4v-2zm14 0h2v-2h-2v2z"/>
        </svg>
      </button>
    </div>
  </div>
</template>

<script>
export default {
  name: 'CanvasControls',
  props: {
    scale: {
      type: Number,
      default: 1
    },
    position: {
      type: Object,
      default: () => ({ x: 0, y: 0 })
    }
  },
  methods: {
    zoomIn() {
      this.$emit('zoom', { delta: 0.1, center: null })
    },
    zoomOut() {
      this.$emit('zoom', { delta: -0.1, center: null })
    },
    resetViewport() {
      this.$emit('reset')
    }
  }
}
</script>

