<template>
  <div class="canvas-container" ref="container" @wheel="handleWheel">
    <v-stage
      ref="stage"
      :config="configKonva"
      @mousedown="handleMouseDown"
      @mousemove="handleMouseMove"
      @mouseup="handleMouseUp"
      @click="handleClick"
    >
      <v-layer ref="gridLayer">
        <v-rect
          :config="gridConfig"
        ></v-rect>
      </v-layer>
      <v-layer
        ref="layer"
        :config="{
          draggable: true,
          x: viewportPosition.x,
          y: viewportPosition.y,
          scaleX: scale,
          scaleY: scale
        }"
        @dragmove="onLayerDragMove"
        @dragend="onLayerDragEnd"
      >
        <v-rect
          v-for="rect in filteredRects"
          :key="rect.name"
          :config="{
            x: Math.min(rect.x, rect.x + rect.width),
            y: Math.min(rect.y, rect.y + rect.height),
            width: Math.abs(rect.width),
            height: Math.abs(rect.height),
            fillEnable: false,
            strokeEnabled: true,
            stroke: '#000',
            strokeWidth: 1,
            name: rect.name,
            id: 'rect',
            scaleX: rect.scaleX,
            scaleY: rect.scaleY,
            draggable: rect.draggable,
          }"
          @dragend="handleShapeDragEnd"
        >
        </v-rect>
        <v-ellipse
          v-for="cir in filteredCircles"
          :key="cir.name"
          :config="{
            x: cir.x,
            y: cir.y,
            radiusX: Math.abs(cir.radiusX),
            radiusY: Math.abs(cir.radiusY),
            strokeEnabled: true,
            stroke: '#000',
            strokeWidth: 1,
            name: cir.name,
            scaleX: cir.scaleX,
            scaleY: cir.scaleY,
            draggable: cir.draggable,
            fillEnable: false,
          }"
          @dragend="handleShapeDragEnd"
        ></v-ellipse>
        <v-regular-polygon
          v-for="triangle in filteredTriangles"
          :key="triangle.name"
          :config="{
            x: triangle.x,
            y: triangle.y,
            sides: 3,
            radius: Math.abs(triangle.radius),
            strokeEnabled: true,
            strokeWidth: 1,
            stroke: '#000',
            name: triangle.name,
            scaleX: triangle.scaleX,
            scaleY: triangle.scaleY,
            draggable: triangle.draggable,
            fillEnable: false,
          }"
          @dragend="handleShapeDragEnd"
        ></v-regular-polygon>
        <v-regular-polygon
          v-for="pentagon in filteredPentagons"
          :key="pentagon.name"
          :config="{
            x: pentagon.x,
            y: pentagon.y,
            sides: 5,
            radius: Math.abs(pentagon.radius),
            strokeEnabled: true,
            strokeWidth: 1,
            stroke: '#000',
            name: pentagon.name,
            scaleX: pentagon.scaleX,
            scaleY: pentagon.scaleY,
            draggable: pentagon.draggable,
            fillEnable: false,
          }"
          @dragend="handleShapeDragEnd"
        ></v-regular-polygon>
        <v-regular-polygon
          v-for="hexagon in filteredHexagons"
          :key="hexagon.name"
          :config="{
            x: hexagon.x,
            y: hexagon.y,
            sides: 6,
            radius: Math.abs(hexagon.radius),
            strokeEnabled: true,
            strokeWidth: 1,
            stroke: '#000',
            name: hexagon.name,
            scaleX: hexagon.scaleX,
            scaleY: hexagon.scaleY,
            draggable: hexagon.draggable,
            fillEnable: false,
          }"
          @dragend="handleShapeDragEnd"
        ></v-regular-polygon>
        <v-arc
          v-for="arc in filteredArcs"
          :key="arc.name"
          :config="{
            x: arc.x,
            y: arc.y,
            innerRadius: Math.abs(arc.innerRadius),
            outerRadius: Math.abs(arc.outerRadius),
            angle: arc.angle,
            name: arc.name,
            scaleX: arc.scaleX,
            scaleY: arc.scaleY,
            draggable: arc.draggable,
            strokeEnabled: true,
            strokeWidth: 1,
            stroke: '#000',
            fillEnable: false,
          }"
          @dragend="handleShapeDragEnd"
        ></v-arc>
        <v-line
          v-for="line in filteredLines"
          :key="line.name"
          :config="{
            points: line.points,
            offset: line.offset,
            name: line.name,
            strokeEnabled: true,
            strokeWidth: 1,
            stroke: '#000',
            lineCap: 'round',
            lineJoin: 'round',
            scaleX: line.scaleX,
            scaleY: line.scaleY,
            draggable: line.draggable,
          }"
          @dragend="handleShapeDragEnd"
        ></v-line>
        <v-text
          v-for="text in filteredTexts"
          :key="text.name"
          @dblclick="editText"
          :config="{
            x: text.x,
            y: text.y,
            offset: text.offset,
            text: 'hello world',
            fontSize: Math.abs(text.fontSize),
            fontFamily: 'Arial',
            name: text.name,
            strokeEnabled: false,
            fill: '#000',
            fillEnabled: true,
            scaleX: text.scaleX,
            scaleY: text.scaleY,
            draggable: text.draggable,
          }"
          @dragend="handleShapeDragEnd"
        ></v-text>
        <v-image
          v-for="image in filteredImages"
          :key="image.name"
          :config="{
            x: image.x,
            y: image.y,
            image: image.imageEl,
            width: image.width,
            height: image.height,
            name: image.name,
            scaleX: image.scaleX,
            scaleY: image.scaleY,
            draggable: image.draggable,
          }"
          @dragend="handleShapeDragEnd"
        ></v-image>
        <v-line
          v-for="bezier in filteredBeziers"
          :key="bezier.name"
          :config="{
            points: bezier.points,
            stroke: bezier.stroke || '#000',
            strokeWidth: bezier.strokeWidth || 2,
            lineCap: 'round',
            lineJoin: 'round',
            name: bezier.name,
            scaleX: bezier.scaleX,
            scaleY: bezier.scaleY,
            draggable: bezier.draggable,
            strokeEnabled: true,
            tension: 1.0
          }"
          @dragend="handleShapeDragEnd"
        ></v-line>
        <v-line
          v-for="path in filteredPaths"
          :key="path.name"
          :config="{
            points: path.points,
            stroke: path.stroke || '#000',
            strokeWidth: path.strokeWidth || 2,
            lineCap: 'round',
            lineJoin: 'round',
            closed: true,
            name: path.name,
            scaleX: path.scaleX,
            scaleY: path.scaleY,
            draggable: path.draggable,
          }"
          @dragend="handleShapeDragEnd"
        ></v-line>
        <v-rect
          :config="{
            ...this.rectBox,
            stroke: '#1D83FF',
            strokeWidth: 0.8,
            fill: 'rgba(29, 131, 255, .2)',
            listening: false,
            id: 'selectBox',
          }"
          ref="rectBox"
        ></v-rect>
        <v-transformer ref="transformer" />
      </v-layer>
    </v-stage>
    <CanvasControls
      :scale="scale"
      :position="viewportPosition"
      @zoom="handleZoom"
      @reset="resetViewport"
    />
    <MiniMap
      v-if="showMiniMap"
      :stageWidth="configKonva.width"
      :stageHeight="configKonva.height"
      :viewportPosition="viewportPosition"
      :scale="scale"
      @viewport-change="handleViewportChange"
      @close="showMiniMap = false"
    />
    <CoordinateInfo :mousePosition="mousePosition" />
  </div>
</template>

<script>
import Konva from 'konva'
import { delShape, drawByDown, setAttr } from '../../utils/utils'
import CanvasControls from './CanvasControls.vue'
import MiniMap from './MiniMap.vue'
import CoordinateInfo from './CoordinateInfo.vue'

let x1, y1, x2, y2
let transformerNode = ''
const GUIDELINE_OFFSET = 5
const MIN_SCALE = 0.1
const MAX_SCALE = 5

export default {
  name: 'Canvas',
  components: {
    CanvasControls,
    MiniMap,
    CoordinateInfo
  },
  props: {
    arrowType: {
      type: String,
      default: 'arrow'
    },
    rects: {
      type: Array,
      default: () => []
    },
    circles: {
      type: Array,
      default: () => []
    },
    triangles: {
      type: Array,
      default: () => []
    },
    pentagons: {
      type: Array,
      default: () => []
    },
    hexagons: {
      type: Array,
      default: () => []
    },
    arcs: {
      type: Array,
      default: () => []
    },
    lines: {
      type: Array,
      default: () => []
    },
    texts: {
      type: Array,
      default: () => []
    },
    images: {
      type: Array,
      default: () => []
    },
    beziers: {
      type: Array,
      default: () => []
    },
    paths: {
      type: Array,
      default: () => []
    },
    groups: {
      type: Array,
      default: () => []
    },
    selectedShapeName: {
      type: String,
      default: ''
    },
    attr: {
      type: Object,
      default: () => ({})
    }
  },
  data() {
    return {
      isDrawing: false,
      down: false,
      configKonva: {
        width: 0,
        height: 0
      },
      rectBox: {
        visible: false,
        width: 0,
        height: 0,
        x: 0,
        y: 0,
      },
      scale: 1,
      viewportPosition: { x: 0, y: 0 },
      gridSize: 20,
      showMiniMap: true,
      mousePosition: { x: 0, y: 0 },
      useVirtualRendering: true, // 启用虚拟化渲染
    }
  },
  computed: {
    gridConfig() {
      const canvasWidth = this.configKonva.width || 10000
      const canvasHeight = this.configKonva.height || 10000
      return {
        x: -5000,
        y: -5000,
        width: canvasWidth + 10000,
        height: canvasHeight + 10000,
        fill: 'transparent',
        strokeEnabled: false,
        fillPatternImage: this.createGridPattern(),
        fillPatternRepeat: 'repeat'
      }
    },
    viewportBounds() {
      // 计算当前视口的边界
      const stageWidth = this.configKonva.width
      const stageHeight = this.configKonva.height
      const viewportX = this.viewportPosition.x
      const viewportY = this.viewportPosition.y
      const scale = this.scale
      
      // 考虑缩放和视口位置，计算实际可见区域
      return {
        left: viewportX - stageWidth / scale,
        top: viewportY - stageHeight / scale,
        right: viewportX + stageWidth / scale,
        bottom: viewportY + stageHeight / scale
      }
    },
    filteredRects() {
      return this.rects.filter(r => this.isShapeInViewport({...r, type: 'rect'}))
    },
    filteredCircles() {
      return this.circles.filter(c => this.isShapeInViewport({...c, type: 'circle'}))
    },
    filteredTriangles() {
      return this.triangles.filter(t => this.isShapeInViewport({...t, type: 'triangle'}))
    },
    filteredPentagons() {
      return this.pentagons.filter(p => this.isShapeInViewport({...p, type: 'pentagon'}))
    },
    filteredHexagons() {
      return this.hexagons.filter(h => this.isShapeInViewport({...h, type: 'hexagon'}))
    },
    filteredArcs() {
      return this.arcs.filter(a => this.isShapeInViewport({...a, type: 'arc'}))
    },
    filteredLines() {
      return this.lines.filter(l => this.isShapeInViewport({...l, type: 'line'}))
    },
    filteredTexts() {
      return this.texts.filter(t => this.isShapeInViewport({...t, type: 'text'}))
    },
    filteredImages() {
      return this.images.filter(i => this.isShapeInViewport({...i, type: 'image'}))
    },
    filteredBeziers() {
      return this.beziers.filter(b => this.isShapeInViewport({...b, type: 'bezier'}))
    },
    filteredPaths() {
      return this.paths.filter(p => this.isShapeInViewport({...p, type: 'path'}))
    }
  },
  mounted() {
    this.initCanvasSize()
    window.addEventListener('resize', this.handleResize)
    const stage = this.$refs.stage?.getNode()
    if (stage) {
      stage.on('mousemove', this.handleStageMouseMove)
    }
  },
  beforeDestroy() {
    window.removeEventListener('resize', this.handleResize)
    const stage = this.$refs.stage?.getNode()
    if (stage) {
      stage.off('mousemove', this.handleStageMouseMove)
    }
  },
  methods: {
    createGridPattern() {
      const canvas = document.createElement('canvas')
      const size = this.gridSize
      canvas.width = size
      canvas.height = size
      const ctx = canvas.getContext('2d')
      
      ctx.strokeStyle = '#e8e8e8'
      ctx.lineWidth = 1
      ctx.beginPath()
      ctx.moveTo(0, 0)
      ctx.lineTo(size, 0)
      ctx.lineTo(size, size)
      ctx.lineTo(0, size)
      ctx.lineTo(0, 0)
      ctx.stroke()
      
      return canvas
    },
    handleWheel(e) {
      e.preventDefault()
      const delta = e.deltaY > 0 ? -0.1 : 0.1
      const stage = this.$refs.stage?.getNode()
      if (!stage) return
      
      const pointerPos = stage.getPointerPosition()
      this.handleZoom({ delta, center: pointerPos || null })
    },
    handleZoom({ delta, center }) {
      let newScale = this.scale * (1 + delta)
      newScale = Math.max(MIN_SCALE, Math.min(MAX_SCALE, newScale))
      
      if (newScale === this.scale) return
      
      const oldScale = this.scale
      this.scale = newScale
      
      if (center) {
        const stage = this.$refs.stage?.getNode()
        if (stage) {
          const scaleDiff = newScale / oldScale
          this.viewportPosition.x = center.x - (center.x - this.viewportPosition.x) * scaleDiff
          this.viewportPosition.y = center.y - (center.y - this.viewportPosition.y) * scaleDiff
        }
      }
    },
    handleViewportChange(position) {
      this.viewportPosition = position
    },
    handleStageMouseMove(e) {
      const stage = this.$refs.stage?.getNode()
      if (stage) {
        const pointerPos = stage.getPointerPosition()
        if (pointerPos) {
          this.mousePosition = pointerPos
        }
      }
    },
    resetViewport() {
      this.scale = 1
      this.viewportPosition = { x: 0, y: 0 }
    },
    initCanvasSize() {
      const container = this.$el
      console.log('Canvas: initCanvasSize called', { container: !!container, clientWidth: container?.clientWidth, clientHeight: container?.clientHeight })
      if (container) {
        this.configKonva = {
          width: container.clientWidth,
          height: container.clientHeight
        }
        console.log('Canvas: initialized size', { width: container.clientWidth, height: container.clientHeight })
      }
    },
    handleResize() {
      this.initCanvasSize()
    },
    handleMouseDown(e) {
      console.log('Canvas: handleMouseDown called', { target: e.target?.className, arrowType: this.arrowType, isStage: e.target === e.target.getStage() })
      
      if (this.arrowType === 'arrow') {
        if (e.target !== e.target.getStage()) return
        
        x1 = this.$refs.stage.getNode().getPointerPosition().x
        y1 = this.$refs.stage.getNode().getPointerPosition().y
        x2 = this.$refs.stage.getNode().getPointerPosition().x
        y2 = this.$refs.stage.getNode().getPointerPosition().y

        this.rectBox = {
          visible: true,
          width: 0,
          height: 0,
          x: 0,
          y: 0,
        }
        transformerNode = this.$refs.transformer.getNode()
        transformerNode.getLayer().draw()
        this.down = true
        this.isDrawing = true
        return
      }
      
      this.down = true
      this.isDrawing = true
      
      const pos = this.$refs.stage.getNode().getPointerPosition()
      console.log('Canvas: emitting draw-start', { pos, arrowType: this.arrowType })
      this.$emit('draw-start', pos, this.arrowType)
    },
    handleMouseMove(e) {
      console.log('Canvas: handleMouseMove called', { isDrawing: this.isDrawing, arrowType: this.arrowType })
      if (!this.isDrawing) return
      if (this.arrowType === 'arrow') {
        if (!this.rectBox.visible) return
        x2 = this.$refs.stage.getNode().getPointerPosition().x
        y2 = this.$refs.stage.getNode().getPointerPosition().y
        this.rectBox = {
          x: Math.min(x1, x2),
          y: Math.min(y1, y2),
          width: Math.abs(x2 - x1),
          height: Math.abs(y2 - y1),
          visible: true,
        }
        transformerNode.getLayer().batchDraw()
      } else {
        const pos = this.$refs.stage.getNode().getPointerPosition()
        console.log('Canvas: emitting draw-move', { pos, arrowType: this.arrowType })
        this.$emit('draw-move', pos, this.arrowType, e.evt.shiftKey)
      }
    },
    handleMouseUp() {
      console.log('Canvas: handleMouseUp called', { arrowType: this.arrowType })
      this.isDrawing = false
      this.down = false
      if (this.arrowType === 'arrow') {
        if (!this.rectBox.visible) return
        setTimeout(() => {
          this.rectBox.visible = false
          transformerNode.getLayer().batchDraw()
        })
        const shapes = this.$refs.stage.getNode().find(node => {
          if (node.getClassName() === 'Ellipse' || node.id() === 'rect' || node.getClassName() === 'RegularPolygon' || node.getClassName() === 'Arc' || node.getClassName() === 'Line' || node.getClassName() === 'Text' || node.getClassName() === 'Image') return true
        }).toArray()
        const box = this.$refs.rectBox.getNode().getClientRect()
        const selected = shapes.filter((shape) =>
          Konva.Util.haveIntersection(box, shape.getClientRect())
        )
        if (selected.length === 1) {
          const selectedName = selected[0].name()
          const attrs = selected[0].getAttrs()
          const type = selectedName.split('-')[0]
          const newAttr = setAttr(type, attrs, this.attr)
          this.$emit('select-shape', selectedName, newAttr)
        } else {
          this.$emit('select-shape', '', {})
        }
        transformerNode.nodes(selected)
        transformerNode.getLayer().batchDraw()
      } else {
        console.log('Canvas: emitting draw-end')
        this.$emit('draw-end')
      }
    },
    handleClick(e) {
      if (this.arrowType === 'arrow') {
        transformerNode = this.$refs.transformer.getNode()
        if (this.rectBox.visible) return
        if (e.target === e.target.getStage()) {
          this.$emit('select-shape', '', {})
          transformerNode.nodes([])
          transformerNode.getLayer().draw()
          return
        }
        if (e.target.id() === 'rect' || e.target.getClassName() === 'Ellipse' || e.target.getClassName() === 'RegularPolygon' || e.target.getClassName() === 'Arc' || e.target.getClassName() === 'Line' || e.target.getClassName() === 'Text' || e.target.getClassName() === 'Image') {
          const metaPressed = e.evt.shiftKey || e.evt.ctrlKey || e.evt.metaKey
          const isSelected = transformerNode.nodes().indexOf(e.target) >= 0
          if (!metaPressed && !isSelected) {
            const selectedName = e.target.name()
            const attrs = e.target.getAttrs()
            const type = selectedName.split('-')[0]
            const newAttr = setAttr(type, attrs, this.attr)
            this.$emit('select-shape', selectedName, newAttr)
            transformerNode.nodes([e.target])
          } else if (metaPressed && isSelected) {
            const nodes = transformerNode.nodes().slice()
            nodes.splice(nodes.indexOf(e.target), 1)
            if (nodes.length === 1) {
              const selectedName = nodes[0].name()
              const attrs = nodes[0].getAttrs()
              const type = selectedName.split('-')[0]
              const newAttr = setAttr(type, attrs, this.attr)
              this.$emit('select-shape', selectedName, newAttr)
            } else {
              this.$emit('select-shape', '', {})
            }
            transformerNode.nodes(nodes)
          } else if (metaPressed && !isSelected) {
            const nodes = transformerNode.nodes().concat([e.target])
            if (nodes.length === 1) {
              const selectedName = nodes[0].name()
              const attrs = nodes[0].getAttrs()
              const type = selectedName.split('-')[0]
              const newAttr = setAttr(type, attrs, this.attr)
              this.$emit('select-shape', selectedName, newAttr)
            } else {
              this.$emit('select-shape', '', {})
            }
            transformerNode.nodes(nodes)
          }
          transformerNode.getLayer().draw()
        }
      }
    },
    editText(e) {
      e.target.hide()
      if (!transformerNode) {
        transformerNode = this.$refs.transformer.getNode()
      }
      const selectedName = e.target.name()
      const attrs = e.target.getAttrs()
      const type = selectedName.split('-')[0]
      const newAttr = setAttr(type, attrs, this.attr)
      this.$emit('select-shape', selectedName, newAttr)
      transformerNode.nodes([e.target])
      transformerNode.hide()
      transformerNode.getLayer().draw()
      const textPosition = e.target.absolutePosition()
      const stageBox = this.$refs.stage.getNode().container().getBoundingClientRect()
      const offset = e.target.getAttr('offset')
      const areaPosition = {
        x: stageBox.left + textPosition.x - offset.x,
        y: stageBox.top + textPosition.y - offset.y
      }
      this.$emit('edit-text', e.target, areaPosition, offset)
    },
    onLayerDragMove(e) {
      const layer = this.$refs.layer.getNode()
      layer.find('.guid-line').destroy()
      const lineGuideStops = this.getLineGuideStops(e.target)
      const itemBounds = this.getObjectSnappingEdges(e.target)
      const guides = this.getGuides(lineGuideStops, itemBounds)
      if (!guides.length) {
        return
      }
      this.drawGuides(guides)
    },
    getLineGuideStops(skipShape) {
      const stage = this.$refs.stage.getNode()
      // 考虑视口位置，获取当前可见区域的中心
      const stageWidth = stage.width()
      const stageHeight = stage.height()
      const viewportX = this.viewportPosition.x
      const viewportY = this.viewportPosition.y
      
      // 计算可见区域的中心
      const visibleCenterX = viewportX + stageWidth / 2
      const visibleCenterY = viewportY + stageHeight / 2
      
      let vertical = [visibleCenterX - stageWidth, visibleCenterX, visibleCenterX + stageWidth]
      let horizontal = [visibleCenterY - stageHeight, visibleCenterY, visibleCenterY + stageHeight]
      
      stage.find('Rect, Ellipse, RegularPolygon, Line, Arc, Text, Image').forEach((guideItem) => {
        if (guideItem === skipShape) {
          return
        }
        const box = guideItem.getClientRect()
        vertical.push([box.x, box.x + box.width, box.x + box.width / 2])
        horizontal.push([box.y, box.y + box.height, box.y + box.height / 2])
      })
      return {
        vertical: vertical.flat(),
        horizontal: horizontal.flat(),
      }
    },
    getObjectSnappingEdges(node) {
      const box = node.getClientRect()
      const absPos = node.absolutePosition()

      return {
        vertical: [
          {
            guide: Math.round(box.x),
            offset: Math.round(absPos.x - box.x),
            snap: 'start',
          },
          {
            guide: Math.round(box.x + box.width / 2),
            offset: Math.round(absPos.x - box.x - box.width / 2),
            snap: 'center',
          },
          {
            guide: Math.round(box.x + box.width),
            offset: Math.round(absPos.x - box.x - box.width),
            snap: 'end',
          },
        ],
        horizontal: [
          {
            guide: Math.round(box.y),
            offset: Math.round(absPos.y - box.y),
            snap: 'start',
          },
          {
            guide: Math.round(box.y + box.height / 2),
            offset: Math.round(absPos.y - box.y - box.height / 2),
            snap: 'center',
          },
          {
            guide: Math.round(box.y + box.height),
            offset: Math.round(absPos.y - box.y - box.height),
            snap: 'end',
          },
        ],
      }
    },
    checkBounds(node) {
      const stage = this.$refs.stage.getNode()
      const box = node.getClientRect()
      const pos = node.position()
      
      let newX = pos.x
      let newY = pos.y
      
      if (box.x < 0) {
        newX = newX - box.x
      }
      if (box.y < 0) {
        newY = newY - box.y
      }
      if (box.x + box.width > stage.width()) {
        newX = stage.width() - box.width - (box.x - pos.x)
      }
      if (box.y + box.height > stage.height()) {
        newY = stage.height() - box.height - (box.y - pos.y)
      }
      
      if (newX !== pos.x || newY !== pos.y) {
        node.position({ x: newX, y: newY })
        return true
      }
      return false
    },
    getGuides(lineGuideStops, itemBounds) {
      let resultV = []
      let resultH = []

      lineGuideStops.vertical.forEach((lineGuide) => {
        itemBounds.vertical.forEach((itemBound) => {
          const diff = Math.abs(lineGuide - itemBound.guide)
          if (diff < GUIDELINE_OFFSET) {
            resultV.push({
              lineGuide: lineGuide,
              diff: diff,
              snap: itemBound.snap,
              offset: itemBound.offset,
            })
          }
        })
      })

      lineGuideStops.horizontal.forEach((lineGuide) => {
        itemBounds.horizontal.forEach((itemBound) => {
          const diff = Math.abs(lineGuide - itemBound.guide)
          if (diff < GUIDELINE_OFFSET) {
            resultH.push({
              lineGuide: lineGuide,
              diff: diff,
              snap: itemBound.snap,
              offset: itemBound.offset,
            })
          }
        })
      })

      let guides = []
      const minV = resultV.sort((a, b) => a.diff - b.diff)[0]
      const minH = resultH.sort((a, b) => a.diff - b.diff)[0]
      if (minV) {
        guides.push({
          lineGuide: minV.lineGuide,
          offset: minV.offset,
          orientation: 'V',
          snap: minV.snap,
        })
      }
      if (minH) {
        guides.push({
          lineGuide: minH.lineGuide,
          offset: minH.offset,
          orientation: 'H',
          snap: minH.snap,
        })
      }
      return guides
    },
    drawGuides(guides) {
      const layer = this.$refs.layer.getNode()
      guides.forEach((lg) => {
        if (lg.orientation === 'H') {
          const line = new Konva.Line({
            points: [-6000, 0, 6000, 0],
            stroke: 'rgb(0, 161, 255)',
            strokeWidth: 1,
            name: 'guid-line',
            dash: [4, 6],
          })
          layer.add(line)
          line.absolutePosition({
            x: 0,
            y: lg.lineGuide,
          })
          layer.batchDraw()
        } else if (lg.orientation === 'V') {
          const line = new Konva.Line({
            points: [0, -6000, 0, 6000],
            stroke: 'rgb(0, 161, 255)',
            strokeWidth: 1,
            name: 'guid-line',
            dash: [4, 6],
          })
          layer.add(line)
          line.absolutePosition({
            x: lg.lineGuide,
            y: 0
          })
          layer.batchDraw()
        }
      })
    },
    onLayerDragEnd() {
      const layer = this.$refs.layer.getNode()
      layer.find('.guid-line').destroy()
      layer.batchDraw()
    },
    handleShapeDragEnd(e) {
      const node = e.target
      const boundsChanged = this.checkBounds(node)
      if (boundsChanged) {
        node.getLayer().batchDraw()
        this.$emit('shape-moved', node)
      }
    },
    getStage() {
      return this.$refs.stage.getNode()
    },
    getTransformer() {
      return this.$refs.transformer.getNode()
    },
    isShapeInViewport(shape) {
      if (!this.useVirtualRendering) return true
      
      const bounds = this.viewportBounds
      
      // 对于不同类型的图形，检查其边界是否与视口相交
      if (shape.type === 'rect') {
        const x = Math.min(shape.x, shape.x + shape.width)
        const y = Math.min(shape.y, shape.y + shape.height)
        const width = Math.abs(shape.width)
        const height = Math.abs(shape.height)
        
        return !(x + width < bounds.left || x > bounds.right || y + height < bounds.top || y > bounds.bottom)
      } else if (shape.type === 'circle' || shape.type === 'ellipse') {
        const x = shape.x
        const y = shape.y
        const radiusX = Math.abs(shape.radiusX || shape.radius)
        const radiusY = Math.abs(shape.radiusY || shape.radius)
        
        return !(x + radiusX < bounds.left || x - radiusX > bounds.right || y + radiusY < bounds.top || y - radiusY > bounds.bottom)
      } else if (shape.type === 'line' || shape.type === 'bezier' || shape.type === 'path') {
        // 对于线条，检查其是否与视口相交
        const points = shape.points
        for (let i = 0; i < points.length; i += 2) {
          const x = points[i]
          const y = points[i + 1]
          if (x >= bounds.left && x <= bounds.right && y >= bounds.top && y <= bounds.bottom) {
            return true
          }
        }
        return false
      } else if (shape.type === 'text') {
        const x = shape.x
        const y = shape.y
        const fontSize = Math.abs(shape.fontSize)
        
        return !(x + fontSize < bounds.left || x > bounds.right || y + fontSize < bounds.top || y > bounds.bottom)
      } else if (shape.type === 'image') {
        const x = shape.x
        const y = shape.y
        const width = shape.width
        const height = shape.height
        
        return !(x + width < bounds.left || x > bounds.right || y + height < bounds.top || y > bounds.bottom)
      } else if (shape.type === 'arc') {
        const x = shape.x
        const y = shape.y
        const radius = Math.abs(shape.outerRadius)
        
        return !(x + radius < bounds.left || x - radius > bounds.right || y + radius < bounds.top || y - radius > bounds.bottom)
      } else if (shape.type === 'triangle' || shape.type === 'pentagon' || shape.type === 'hexagon') {
        const x = shape.x
        const y = shape.y
        const radius = Math.abs(shape.radius)
        
        return !(x + radius < bounds.left || x - radius > bounds.right || y + radius < bounds.top || y - radius > bounds.bottom)
      }
      
      return true
    }
  }
}
</script>

