<template>
  <div v-if="visible" class="onboarding-overlay">
    <div class="overlay-backdrop" @click="handleBackdropClick"></div>
    <div class="onboarding-step" :class="{ 'active': currentStep === step.index }" v-for="step in steps" :key="step.index">
      <div 
        class="highlight-area" 
        :style="{
          left: step.position.x + '%',
          top: step.position.y + '%',
          width: step.position.width + '%',
          height: step.position.height + '%'
        }"
      ></div>
      <div class="step-content" :style="step.contentPosition">
        <h3>{{ step.title }}</h3>
        <p>{{ step.description }}</p>
        <div class="step-actions">
          <button v-if="step.index > 0" class="btn btn-secondary" @click="prevStep">上一步</button>
          <button class="btn btn-primary" @click="nextStep">{{ step.index === steps.length - 1 ? '完成' : '下一步' }}</button>
        </div>
      </div>
    </div>
    <button class="skip-btn" @click="skip">跳过</button>
  </div>
</template>

<script>
export default {
  name: 'OnboardingGuide',
  data() {
    return {
      visible: false,
      currentStep: 0,
      steps: [
        {
          index: 0,
          title: '欢迎使用绘图板',
          description: '这是一个功能强大的在线绘图工具，让我带你快速了解如何使用它。',
          position: { x: 0, y: 0, width: 100, height: 100 },
          contentPosition: { top: '20%', left: '50%', transform: 'translateX(-50%)' }
        },
        {
          index: 1,
          title: '选择绘图工具',
          description: '从左侧工具栏选择你需要的绘图工具，如矩形、椭圆、三角形等。',
          position: { x: 0, y: 0, width: 8, height: 100 },
          contentPosition: { top: '50%', left: '15%', transform: 'translateY(-50%)' }
        },
        {
          index: 2,
          title: '缩放画布',
          description: '使用鼠标滚轮可以缩放画布，也可以使用右下角的缩放控制按钮。',
          position: { x: 85, y: 80, width: 15, height: 15 },
          contentPosition: { bottom: '20%', right: '20%' }
        },
        {
          index: 3,
          title: '平移画布',
          description: '直接拖拽画布可以平移，也可以使用小地图进行导航。',
          position: { x: 85, y: 50, width: 15, height: 25 },
          contentPosition: { bottom: '50%', right: '20%' }
        },
        {
          index: 4,
          title: '查看坐标',
          description: '左上角显示当前鼠标在画布上的坐标位置，帮助你精确定位。',
          position: { x: 0, y: 0, width: 20, height: 10 },
          contentPosition: { top: '15%', left: '25%' }
        },
        {
          index: 5,
          title: '开始创作',
          description: '现在你已经了解了基本操作，开始你的创作之旅吧！',
          position: { x: 20, y: 20, width: 60, height: 60 },
          contentPosition: { top: '20%', left: '50%', transform: 'translateX(-50%)' }
        }
      ]
    }
  },
  mounted() {
    this.checkShowOnboarding()
  },
  methods: {
    checkShowOnboarding() {
      const hasSeenOnboarding = localStorage.getItem('hasSeenOnboarding')
      if (!hasSeenOnboarding) {
        setTimeout(() => {
          this.visible = true
        }, 1000)
      }
    },
    nextStep() {
      if (this.currentStep < this.steps.length - 1) {
        this.currentStep++
      } else {
        this.complete()
      }
    },
    prevStep() {
      if (this.currentStep > 0) {
        this.currentStep--
      }
    },
    skip() {
      this.complete()
    },
    complete() {
      this.visible = false
      localStorage.setItem('hasSeenOnboarding', 'true')
    },
    handleBackdropClick() {
      this.complete()
    },
    show() {
      this.visible = true
      this.currentStep = 0
    }
  }
}
</script>

